import argparse
import os
import sys


def session_sync():
    print("=== SESSION SYNC (Engine Layer) ===")
    print("SYSTEM DIRECTIVE TO AI: Review the injected task_plan.md and progress.md.")

    # Check if there are dangling tasks in progress.md
    if os.path.exists("progress.md"):
        with open("progress.md", "r") as f:
            content = f.read()
            if "[ ]" in content:
                print("WARNING: Unfinished tasks detected in progress.md.")
                print(
                    "AI ACTION: Ask the user if these should be moved back to task_plan.md before starting a new session."
                )
                return

    print(
        "AI ACTION: Prompt the user with: 'Ready to proceed? Confirm to start the session.' Do not execute any code until confirmed."
    )


def milestone_sync():
    print("=== MILESTONE GATE (Spec Layer) ===")
    if os.path.exists("findings.md"):
        with open("findings.md", "r") as f:
            content = f.read()
            if len(content.strip()) > 20:  # More than just a header
                print("ACTION REQUIRED: Unarchived findings detected.")
                print(
                    "AI ACTION: 1. Read findings.md. 2. Ask user for permission to archive findings to the Knowledge Layer (e.g., /docs/FRAMEWORK.md). 3. If approved, append them and clear findings.md."
                )
                return
    print(
        "AI ACTION: Audit completed. Ask user to verify docs/milestones/ against implementation."
    )


def audit_sync():
    print("=== GLOBAL INTEGRITY (Spec vs Engine) ===")
    files = [
        "INDEX.md",
        "task_plan.md",
        "ROADMAP.md",
        ".pi/extensions/project-context.ts",
        "CONTEXT/skeletons/autonomedia_skeleton.md",
    ]
    missing = [f for f in files if not os.path.exists(f)]
    if missing:
        print(f"CRITICAL WARNING: Missing core hierarchy files: {missing}")
        print(
            "AI ACTION: Stop immediately. Notify user of missing architectural files."
        )
    else:
        print("Required hierarchy files found.")
        print(
            "AI ACTION: Read ROADMAP.md and task_plan.md. Report any divergence between them. Ask user to verify status report before closing."
        )


def commit_sync():
    print("=== COMMIT/PUSH GATE (History Layer) ===")
    print(
        "AI ACTION: Verify that all tests pass (pytest), linting passes (ruff), and types pass (mypy)."
    )
    print(
        "AI ACTION: Ensure commit message references the current milestone. Ask for HITL confirmation before pushing to remote."
    )


if __name__ == "__main__":
    parser = argparse.ArgumentParser(description="Autonomedia Tri-Tier Synchronization")
    parser.add_argument(
        "tier",
        choices=["session", "milestone", "audit", "commit"],
        help="The synchronization tier to execute",
    )
    args = parser.parse_args()

    if args.tier == "session":
        session_sync()
    elif args.tier == "milestone":
        milestone_sync()
    elif args.tier == "audit":
        audit_sync()
    elif args.tier == "commit":
        commit_sync()
